// Code: Empfänger-Map aufbauen (v14)
// _typ='kunde'  → direkte Kunden-Empfänger
// _typ='gruppe' → Gruppen-Empfänger + ihre Mitglieder mit eigenem Space
// _typ='termin' → Termine mit Kunden- und Gruppen-Relationen
//
// Empfänger-Map: confluencePageId → { confluencePageId, termine[] }
// Duplikat-Schutz: gleicher Termin + gleiche PageID = nur 1x

var today = new Date();
today.setHours(0, 0, 0, 0);
var alleItems = $input.all();

// ── Schritt 1: Kunden-Map aufbauen ──────────────────────────
// kundePageId → { confluencePageId, spaceKey }
var kundeMap = {};
for (var k = 0; k < alleItems.length; k++) {
  var item = alleItems[k].json;
  if (item._typ !== 'kunde') continue;
  if (!item._confluencePageId) continue;
  kundeMap[item._pageId] = {
    confluencePageId: item._confluencePageId,
    spaceKey:         item._spaceKey || ''
  };
}

// ── Schritt 2: Gruppen-Map aufbauen ─────────────────────────
// gruppePageId → { confluencePageId, spaceKey, mitglieder[] }
var gruppeMap = {};
for (var g = 0; g < alleItems.length; g++) {
  var item = alleItems[g].json;
  if (item._typ !== 'gruppe') continue;
  if (!item._confluencePageId) continue;
  gruppeMap[item._pageId] = {
    confluencePageId: item._confluencePageId,
    spaceKey:         item._spaceKey    || '',
    mitglieder:       item._mitglieder  || []
  };
}

// ── Schritt 3: Empfänger-Map aufbauen ───────────────────────
// Key: confluencePageId (eindeutig pro Space)
// Value: { confluencePageId, termine[], termineKeys{} }
var empfaengerMap = {};

function getOrCreate(confPageId) {
  if (!empfaengerMap[confPageId]) {
    empfaengerMap[confPageId] = {
      confluencePageId: confPageId,
      termine:          [],
      _termineKeys:     {}
    };
  }
  return empfaengerMap[confPageId];
}

function addTermin(confPageId, termin) {
  if (!confPageId) return;
  var emp    = getOrCreate(confPageId);
  var dupKey = termin.datumIso + '|' + termin.titel;
  if (emp._termineKeys[dupKey]) return; // Duplikat-Schutz
  emp._termineKeys[dupKey] = true;
  emp.termine.push(termin);
}

// Alle Kunden mit Confluence-Seite als Empfänger anlegen (auch ohne Termine)
var kundeKeys = Object.keys(kundeMap);
for (var ki = 0; ki < kundeKeys.length; ki++) {
  getOrCreate(kundeMap[kundeKeys[ki]].confluencePageId);
}
// Alle Gruppen mit Confluence-Seite als Empfänger anlegen
var gruppeKeys = Object.keys(gruppeMap);
for (var gi = 0; gi < gruppeKeys.length; gi++) {
  getOrCreate(gruppeMap[gruppeKeys[gi]].confluencePageId);
}

// ── Schritt 4: Termine zuordnen ─────────────────────────────
for (var t = 0; t < alleItems.length; t++) {
  var item = alleItems[t].json;
  if (item._typ !== 'termin') continue;

  var datumIso = item._datumIso || '';
  if (!datumIso || new Date(datumIso) < today) continue;

  var termin = {
    datumIso:   datumIso,
    datumStr:   item._datumStr   || '',
    uhrzeitStr: item._uhrzeitStr || '',
    titel:      item._titel      || '',
    ort:        item._ort        || ''
  };

  // Direkte Kunden-Empfänger
  var kundenIds = item._kundenIds || [];
  for (var ki2 = 0; ki2 < kundenIds.length; ki2++) {
    var kId = kundenIds[ki2];
    if (!kId || !kundeMap[kId]) continue;
    addTermin(kundeMap[kId].confluencePageId, termin);
  }

  // Gruppen-Empfänger
  var gruppenIds = item._gruppenIds || [];
  for (var gi2 = 0; gi2 < gruppenIds.length; gi2++) {
    var gId = gruppenIds[gi2];
    if (!gId || !gruppeMap[gId]) continue;
    var gruppe = gruppeMap[gId];

    // 1. Termin in Gruppen-Space
    addTermin(gruppe.confluencePageId, termin);

    // 2. Termin in individuelle Kunden-Spaces der Mitglieder
    for (var mi = 0; mi < gruppe.mitglieder.length; mi++) {
      var mId = gruppe.mitglieder[mi];
      if (!mId || !kundeMap[mId]) continue; // nur Mitglieder mit eigenem Space
      addTermin(kundeMap[mId].confluencePageId, termin);
    }
  }
}

// ── Schritt 5: Ergebnis aufbauen ────────────────────────────
var result = [];
var empKeys = Object.keys(empfaengerMap);
for (var ei = 0; ei < empKeys.length; ei++) {
  var emp = empfaengerMap[empKeys[ei]];
  delete emp._termineKeys; // interne Hilfsstruktur entfernen
  emp.termine.sort(function(a,b){
    return a.datumIso < b.datumIso ? -1 : a.datumIso > b.datumIso ? 1 : 0;
  });
  result.push({ json: emp });
}
return result;

var page     = $json;
var loopItem = $('Loop: Ein Kunde pro Durchlauf').item.json;
var termine  = loopItem.termine || [];

var esc = function(s) {
  return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
};

var pageId       = page.id    || '';
var pageTitle    = page.title || '';
var currentVersion = (page.version && page.version.number) ? page.version.number : 1;
var html = (page.body && page.body.storage && page.body.storage.value)
  ? page.body.storage.value : '';

// Tabelle aufbauen
var tableLocalId = 'termine-tbl-' + pageId + '-0001';
var headerRow = '<tr>'
  + '<th ac:local-id="'+tableLocalId+'-h1"><p><strong>Datum</strong></p></th>'
  + '<th ac:local-id="'+tableLocalId+'-h2"><p><strong>Uhrzeit</strong></p></th>'
  + '<th ac:local-id="'+tableLocalId+'-h3"><p><strong>Titel</strong></p></th>'
  + '<th ac:local-id="'+tableLocalId+'-h4"><p><strong>Ort</strong></p></th>'
  + '</tr>';

var dataRows = '';
for (var ri = 0; ri < termine.length; ri++) {
  var t = termine[ri];
  var rowId = tableLocalId + '-r' + ri;
  dataRows += '<tr ac:local-id="'+rowId+'">'
    + '<td ac:local-id="'+rowId+'-c1"><p>'+esc(t.datumStr)  +'</p></td>'
    + '<td ac:local-id="'+rowId+'-c2"><p>'+esc(t.uhrzeitStr)+'</p></td>'
    + '<td ac:local-id="'+rowId+'-c3"><p>'+esc(t.titel)     +'</p></td>'
    + '<td ac:local-id="'+rowId+'-c4"><p>'+esc(t.ort)       +'</p></td>'
    + '</tr>';
}

var tableHtml = termine.length > 0
  ? '<table data-table-width="760" data-layout="default" ac:local-id="'+tableLocalId+'">'
    + '<tbody>'+headerRow+dataRows+'</tbody></table>'
  : '<p></p>';

var newRTB = '<ac:rich-text-body>' + tableHtml + '</ac:rich-text-body>';

// ── Panel suchen ────────────────────────────────────────────
var panelTitles = [
  'N\u00e4chste Termine','N&auml;chste Termine',
  'N&#228;chste Termine','N&#xE4;chste Termine','N&#xe4;chste Termine',
  'N&#Xe4;chste Termine','Termine'
];
var titleIdx = -1;
for (var ti = 0; ti < panelTitles.length; ti++) {
  titleIdx = html.indexOf(panelTitles[ti]);
  if (titleIdx !== -1) break;
}

// Panel-Makro nach Heading suchen
var panelStart = -1;
var panelEnd_full = -1;
var panelBlock = '';

if (titleIdx !== -1) {
  var panelMacroTag = '<ac:structured-macro ac:name="panel"';
  // Suche Panel-Makro NACH dem Heading (max 2000 Zeichen danach)
  var searchFrom = Math.max(0, titleIdx - 500);
  var candidate  = html.indexOf(panelMacroTag, searchFrom);
  if (candidate !== -1 && candidate < titleIdx + 2000) {
    panelStart = candidate;
    var panelEndTag = '</ac:structured-macro>';
    var panelEnd    = html.indexOf(panelEndTag, panelStart);
    if (panelEnd !== -1) {
      panelEnd_full = panelEnd + panelEndTag.length;
      panelBlock    = html.substring(panelStart, panelEnd_full);
    }
  }
}

if (panelStart !== -1 && panelEnd_full !== -1) {
  // Panel gefunden → rich-text-body ersetzen
  var newPanelBlock;
  var selfClosing = '<ac:rich-text-body />';
  if (panelBlock.indexOf(selfClosing) !== -1) {
    newPanelBlock = panelBlock.replace(selfClosing, newRTB);
  } else {
    var rtbOpen  = '<ac:rich-text-body>';
    var rtbClose = '</ac:rich-text-body>';
    var rtbStart = panelBlock.indexOf(rtbOpen);
    var rtbEnd   = panelBlock.indexOf(rtbClose);
    if (rtbStart !== -1 && rtbEnd !== -1) {
      newPanelBlock = panelBlock.substring(0, rtbStart) + newRTB
        + panelBlock.substring(rtbEnd + rtbClose.length);
    } else {
      // Fallback: Panel-Ende ersetzen
      newPanelBlock = panelBlock.replace('</ac:structured-macro>', newRTB + '</ac:structured-macro>');
    }
  }
  html = html.substring(0, panelStart) + newPanelBlock + html.substring(panelEnd_full);
} else {
  // Panel nicht gefunden → bestehende ac:rich-text-body mit tableLocalId suchen
  // (bereits eingefügte Tabelle ersetzen)
  var existingTable = 'ac:local-id="' + tableLocalId + '"';
  if (html.indexOf(existingTable) !== -1) {
    // Tabelle bereits vorhanden – ganzen Table-Block ersetzen
    var tblStart = html.lastIndexOf('<table', html.indexOf(existingTable));
    var tblEnd   = html.indexOf('</table>', tblStart) + '</table>'.length;
    if (tblStart !== -1 && tblEnd > tblStart) {
      html = html.substring(0, tblStart) + tableHtml + html.substring(tblEnd);
    }
  } else {
    // Absoluter Fallback: ans Ende anhängen (verhindert doppelte Tabellen)
    html = html + tableHtml;
  }
}

return { json: { pageId, pageTitle, newVersion: currentVersion+1, updatedHtml: html } };

// Code: Kunden normalisieren
// Liest Notion-Kunden-Daten und normalisiert Feldnamen
var items = $input.all();
if (!items || items.length === 0) return [];

return items.map(function(item) {
  var p = item.json;
  var confPageId = p.property_confluence_page_i_d
    || p.property_confluence_page_id
    || p.property_confluencepageid
    || '';
  var spaceKey = p.property_confluence_space_key
    || p.property_confluencespacekey
    || p.property_confluence_spacekey
    || '';
  return {
    json: {
      _typ:             'kunde',
      _pageId:          p.id || '',
      _confluencePageId: confPageId,
      _spaceKey:        spaceKey
    }
  };
}).filter(function(i) { return i.json._confluencePageId !== ''; });

var items = $input.all();
if (!items || items.length === 0) return [];

return items.map(function(item) {
  var p = item.json;

  var datumObj = p.property_datum;
  var datumRaw = null;
  if (datumObj && datumObj.start)                                 { datumRaw = datumObj.start; }
  else if (typeof datumObj === 'string' && datumObj.length >= 10) { datumRaw = datumObj; }
  if (!datumRaw) return null;

  var datumIso   = datumRaw.substring(0, 10);
  var dp         = datumIso.split('-');
  var datumStr   = dp[2] + '.' + dp[1] + '.' + dp[0];
  var uhrzeitStr = '';
  var tIdx       = datumRaw.indexOf('T');
  if (tIdx !== -1) { uhrzeitStr = datumRaw.substring(tIdx + 1, tIdx + 6); }

  var kundenRaw  = p.property_kunden     || [];
  var gruppenRaw = p.property_db_gruppen || [];

  return {
    json: {
      _typ:        'termin',
      _datumIso:   datumIso,
      _datumStr:   datumStr,
      _uhrzeitStr: uhrzeitStr,
      _titel:      String(p.property_titel || p.name || 'Kein Titel'),
      _ort:        String(p.property_ort   || ''),
      _kundenIds:  (Array.isArray(kundenRaw)  ? kundenRaw  : [kundenRaw] ).filter(Boolean),
      _gruppenIds: (Array.isArray(gruppenRaw) ? gruppenRaw : [gruppenRaw]).filter(Boolean)
    }
  };
}).filter(Boolean);

var items = $input.all();
if (!items || items.length === 0) return [];

return items.map(function(item) {
  var p = item.json;

  var confPageId = p.property_confluence_page_id || '';
  var spaceKey   = p.property_confluence_space_key || '';
  var mitglieder = p.property_db_kunden || [];
  if (!Array.isArray(mitglieder)) mitglieder = [mitglieder];
  var aktiv = p.property_aktiv !== false;

  return {
    json: {
      _typ:              'gruppe',
      _pageId:           p.id || '',
      _confluencePageId: String(confPageId).trim(),
      _spaceKey:         String(spaceKey).trim(),
      _mitglieder:       mitglieder.filter(Boolean),
      _aktiv:            aktiv
    }
  };
}).filter(function(i) {
  return i.json._confluencePageId !== '' && i.json._aktiv;
});

var items = $input.all();
var summary = items.map(function(i) {
  return {
    pageId:           i.json._pageId || '?',
    confluencePageId: i.json._confluencePageId || 'LEER',
    spaceKey:         i.json._spaceKey || 'LEER'
  };
});
console.log('[DEBUG 1 - Kunden] Anzahl:', items.length);
console.log('[DEBUG 1 - Kunden] Liste:', JSON.stringify(summary));
return items;

var items = $input.all();
var summary = items.map(function(i) {
  return {
    confluencePageId: i.json.confluencePageId || '?',
    termineAnzahl:    (i.json.termine || []).length,
    ersterTermin:     (i.json.termine || [])[0]?.datumStr || '-'
  };
});
console.log('[DEBUG 2 - Empfaenger] Anzahl:', items.length);
console.log('[DEBUG 2 - Empfaenger] Liste:', JSON.stringify(summary));
return items;

var d = $input.item.json;
var loopItem = $('Loop: Ein Kunde pro Durchlauf').item.json;
var anfrageId = loopItem.confluencePageId || '?';
var info;

if (d.error) {
  // n8n continueOnFail-Struktur: { error: { message, status } }
  var errMsg = d.error.message || '';
  var httpStatus = d.error.status || '?';
  var authorizedFalse = errMsg.indexOf('"authorized":false') !== -1;
  var notFound = errMsg.indexOf('No content found') !== -1;
  info = {
    anfrage_confluencePageId: anfrageId,
    status: 'FEHLER',
    http_status: httpStatus,
    authorized: authorizedFalse ? false : 'unbekannt',
    seite_existiert: notFound ? 'NEIN (oder kein Zugriff)' : 'unbekannt',
    fehlertext: errMsg.substring(0, 300)
  };
} else {
  info = {
    anfrage_confluencePageId: anfrageId,
    status: 'OK',
    antwort_id:    d.id || 'FEHLT',
    antwort_title: d.title || 'FEHLT',
    version:       d.version ? d.version.number : '?'
  };
}

console.log('[DEBUG 3 - Confluence Response]', JSON.stringify(info));
return { json: Object.assign({}, d, { _debug_confluence: info }) };
